import { useState, useEffect } from 'react';
import { X } from '@phosphor-icons/react';

const EMPTY = {
  address: '', district: '', bedrooms: 1, floor: 1,
  areaM2: '', price: '', description: '',
  hasParking: false, hasBalcony: false, status: 'AVAILABLE',
};

const STATUS_OPTS = [
  { value: 'AVAILABLE', label: 'Disponible' },
  { value: 'RENTED',    label: 'Alquilado'  },
  { value: 'SOLD',      label: 'Vendido'    },
];

function validate(form) {
  const e = {};
  if (!form.address.trim())           e.address   = 'Requerido';
  if (!form.district.trim())          e.district  = 'Requerido';
  if (form.bedrooms < 1 || form.bedrooms > 20) e.bedrooms = '1–20';
  if (form.floor < 1 || form.floor > 100)      e.floor    = '1–100';
  if (!form.areaM2 || +form.areaM2 <= 0)       e.areaM2   = 'Mayor a 0';
  if (!form.price  || +form.price  <= 0)        e.price    = 'Mayor a 0';
  return e;
}

export default function DepartmentModal({ open, onClose, onSave, initial }) {
  const [form, setForm] = useState(EMPTY);
  const [errors, setErrors] = useState({});
  const [saving, setSaving] = useState(false);
  const isEdit = !!initial;

  useEffect(() => {
    if (open) {
      setForm(initial
        ? { ...EMPTY, ...initial, areaM2: initial.areaM2, price: initial.price }
        : EMPTY
      );
      setErrors({});
    }
  }, [open, initial]);

    if (!open) return;

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleSave = async () => {
    const e = validate(form);
    if (Object.keys(e).length) { setErrors(e); return; }
    setSaving(true);
    try {
      await onSave({
        address:     form.address.trim(),
        district:    form.district.trim(),
        bedrooms:    +form.bedrooms,
        floor:       +form.floor,
        areaM2:      +form.areaM2,
        price:       +form.price,
        description: form.description.trim() || null,
        hasParking:  form.hasParking,
        hasBalcony:  form.hasBalcony,
        status:      form.status,
      });
      onClose();
    } catch (err) {
      const msg = err?.response?.data?.message || 'Error al guardar';
      setErrors({ _global: msg });
    } finally {
      setSaving(false);
    }
  };

  const F = ({ label, name, type = 'text', children, full }) => (
    <div className={`form-group${full ? ' full' : ''}`}>
      <label>{label}</label>
      {children || (
        <input
          type={type}
          value={form[name]}
          onChange={e => set(name, e.target.value)}
          className={errors[name] ? 'invalid' : ''}
        />
      )}
      {errors[name] && <span className="error-msg">{errors[name]}</span>}
    </div>
  );

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal" role="dialog" aria-modal="true" aria-label={isEdit ? 'Editar departamento' : 'Nuevo departamento'}>
        <div className="modal-header">
          <span className="modal-title">{isEdit ? 'Editar departamento' : 'Nuevo departamento'}</span>
          <button className="modal-close" onClick={onClose} aria-label="Cerrar"><X size={18} /></button>
        </div>

        <div className="modal-body">
          {errors._global && (
            <div style={{ background:'#fef2f2', color:'#b91c1c', padding:'10px 12px', borderRadius:6, marginBottom:14, fontSize:13 }}>
              {errors._global}
            </div>
          )}
          <div className="form-grid">
            <F label="DIRECCIÓN" name="address" full />
            <F label="DISTRITO" name="district">
              <input value={form.district} onChange={e => set('district', e.target.value)} className={errors.district ? 'invalid' : ''} />
            </F>
            <F label="ESTADO" name="status">
              <select value={form.status} onChange={e => set('status', e.target.value)}>
                {STATUS_OPTS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
              </select>
            </F>
            <F label="HABITACIONES" name="bedrooms" type="number">
              <input type="number" min={1} max={20} value={form.bedrooms} onChange={e => set('bedrooms', e.target.value)} className={errors.bedrooms ? 'invalid' : ''} />
            </F>
            <F label="PISO" name="floor" type="number">
              <input type="number" min={1} max={100} value={form.floor} onChange={e => set('floor', e.target.value)} className={errors.floor ? 'invalid' : ''} />
            </F>
            <F label="ÁREA (m²)" name="areaM2" type="number">
              <input type="number" min={1} step="0.1" value={form.areaM2} onChange={e => set('areaM2', e.target.value)} className={errors.areaM2 ? 'invalid' : ''} />
            </F>
            <F label="PRECIO ($)" name="price" type="number">
              <input type="number" min={1} value={form.price} onChange={e => set('price', e.target.value)} className={errors.price ? 'invalid' : ''} />
            </F>
            <F label="DESCRIPCIÓN" name="description" full>
              <textarea value={form.description} onChange={e => set('description', e.target.value)} placeholder="Descripción opcional..." />
            </F>
            <div className="form-group">
              <label>AMENIDADES</label>
              <div className="checkbox-row">
                <input type="checkbox" id="parking" checked={form.hasParking} onChange={e => set('hasParking', e.target.checked)} />
                <label htmlFor="parking">Estacionamiento</label>
              </div>
            </div>
            <div className="form-group" style={{justifyContent:'flex-end'}}>
              <label>&nbsp;</label>
              <div className="checkbox-row">
                <input type="checkbox" id="balcony" checked={form.hasBalcony} onChange={e => set('hasBalcony', e.target.checked)} />
                <label htmlFor="balcony">Balcón</label>
              </div>
            </div>
          </div>
        </div>

        <div className="modal-footer">
          <button className="btn btn-ghost" onClick={onClose} disabled={saving}>Cancelar</button>
          <button className="btn btn-primary" onClick={handleSave} disabled={saving}>
            {saving ? 'Guardando...' : (isEdit ? 'Guardar cambios' : 'Crear departamento')}
          </button>
        </div>
      </div>
    </div>
  );
}
